    # Build KMP failure table
    fail = [0] * mb
    k = 0
    for i in range(1, mb):
        while k > 0 and pat_b[k] != pat_b[i]:
            k = fail[k - 1]
        if pat_b[k] == pat_b[i]:
            k += 1
        fail[i] = k
    # Search
    results = []
    results_append = results.append
    j = 0
    for i in range(nb):
        c = text_b[i]
        while j > 0 and pat_b[j] != c:
            j = fail[j - 1]
        if pat_b[j] == c:
            j += 1
        if j == mb:
            results_append(i - mb + 1)
            j = fail[j - 1]
